import{_ as a,c as e,o as m,d as t}from"./plugin-vue_export-helper.d4b2cde8.js";const k='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 1","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 1","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 2.","tags":"vim-2","date":"2021-02-10T00:00:00.000Z"},"relativePath":"texts/shiva-sutra-vimarshini/2/1.md","lastUpdated":1625682784000}',r={},p=t('<div class="stanza"><a href="#s2.1" id="s2.1" class="num">2.1</a><div class="sans"><p>\u0907\u0926\u093E\u0928\u0940\u0902 \u0936\u093E\u0915\u094D\u0924\u094B\u092A\u093E\u092F\u0903 \u092A\u094D\u0930\u0926\u0930\u094D\u0936\u094D\u092F\u0924\u0947\u0964 \u0924\u0924\u094D\u0930 \u0936\u0915\u094D\u0924\u093F\u0930\u094D\u092E\u0928\u094D\u0924\u094D\u0930\u0935\u0940\u0930\u094D\u092F\u0938\u094D\u092B\u093E\u0930\u0930\u0942\u092A\u0947\u0924\u093F \u092A\u094D\u0930\u0925\u092E\u094B\u0928\u094D\u092E\u0947\u0937\u093E\u0928\u094D\u0924\u0938\u0942\u0924\u094D\u0930\u093F\u0924\u0924\u0924\u094D\u0938\u094D\u0935\u0930\u0942\u092A\u0935\u093F\u0935\u0947\u091A\u0928\u092A\u0941\u0930\u0903\u0938\u0930\u092E\u0941\u0928\u094D\u092E\u0947\u0937\u093E\u0928\u094D\u0924\u0930\u092E\u093E\u0930\u092D\u092E\u093E\u0923\u094B \u092E\u0928\u094D\u0924\u094D\u0930\u0938\u094D\u0935\u0930\u0942\u092A\u0902 \u0924\u093E\u0935\u0928\u094D\u0928\u093F\u0930\u0942\u092A\u092F\u0924\u093F\u2014</p><blockquote><p><strong>\u091A\u093F\u0924\u094D\u0924\u0902 \u092E\u0928\u094D\u0924\u094D\u0930\u0903\u0965\u0967\u0965</strong></p></blockquote><p>\u091A\u0947\u0924\u094D\u092F\u0924\u0947 \u0935\u093F\u092E\u0943\u0936\u094D\u092F\u0924\u0947\u093D\u0928\u0947\u0928 \u092A\u0930\u0902 \u0924\u0924\u094D\u0924\u094D\u0935\u092E\u093F\u0924\u093F \u091A\u093F\u0924\u094D\u0924\u0902 \u092A\u0942\u0930\u094D\u0923\u0938\u094D\u092B\u0941\u0930\u0924\u094D\u0924\u093E\u0938\u0924\u0924\u094D\u0924\u094D\u0935\u092A\u094D\u0930\u093E\u0938\u093E\u0926\u092A\u094D\u0930\u0923\u0935\u093E\u0926\u093F\u0935\u093F\u092E\u0930\u094D\u0936\u0930\u0942\u092A\u0902 \u0938\u0902\u0935\u0947\u0926\u0928\u0902 \u0924\u0926\u0947\u0935 \u092E\u0928\u094D\u0924\u094D\u0930\u094D\u092F\u0924\u0947 \u0917\u0941\u092A\u094D\u0924\u092E\u0928\u094D\u0924\u0930\u092D\u0947\u0926\u0947\u0928 \u0935\u093F\u092E\u0943\u0936\u094D\u092F\u0924\u0947 \u092A\u0930\u092E\u0947\u0936\u094D\u0935\u0930\u0930\u0942\u092A\u092E\u0928\u0947\u0928\u0947\u0924\u093F \u0915\u0943\u0924\u094D\u0935\u093E \u092E\u0928\u094D\u0924\u094D\u0930\u0903\u0964 \u0905\u0924 \u090F\u0935 \u091A \u092A\u0930\u0938\u094D\u092B\u0941\u0930\u0924\u094D\u0924\u093E\u0924\u094D\u092E\u0915\u092E\u0928\u0928\u0927\u0930\u094D\u092E\u093E\u0924\u094D\u092E\u0924\u093E \u092D\u0947\u0926\u092E\u092F\u0938\u0902\u0938\u093E\u0930\u092A\u094D\u0930\u0936\u092E\u0928\u093E\u0924\u094D\u092E\u0915\u0924\u094D\u0930\u093E\u0923\u0927\u0930\u094D\u092E\u0924\u093E \u091A\u093E\u0938\u094D\u092F \u0928\u093F\u0930\u0941\u091A\u094D\u092F\u0924\u0947\u0964</p><p>\u0905\u0925 \u091A \u092E\u0928\u094D\u0924\u094D\u0930\u0926\u0947\u0935\u0924\u093E\u0935\u093F\u092E\u0930\u094D\u0936\u092A\u0930\u0924\u094D\u0935\u0947\u0928 \u092A\u094D\u0930\u093E\u092A\u094D\u0924\u0924\u0924\u094D\u0938\u093E\u092E\u0930\u0938\u094D\u092F\u092E\u093E\u0930\u093E\u0927\u0915\u091A\u093F\u0924\u094D\u0924\u092E\u0947\u0935 \u092E\u0928\u094D\u0924\u094D\u0930\u094B \u0928 \u0924\u0941 \u0935\u093F\u091A\u093F\u0924\u094D\u0930\u0935\u0930\u094D\u0923\u0938\u0919\u094D\u0918\u091F\u094D\u091F\u0928\u093E\u092E\u093E\u0924\u094D\u0930\u0915\u092E\u094D\u0964 \u092F\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u092E\u0924\u094D\u0938\u0930\u094D\u0935\u091C\u094D\u091E\u093E\u0928\u094B\u0924\u094D\u0924\u0930\u0947</p><blockquote><p>\u0909\u091A\u094D\u091A\u093E\u0930\u094D\u092F\u092E\u093E\u0923\u093E \u092F\u0947 \u092E\u0928\u094D\u0924\u094D\u0930\u093E \u0928 \u092E\u0928\u094D\u0924\u094D\u0930\u093E\u0902\u0936\u094D\u091A\u093E\u092A\u093F \u0924\u093E\u0928\u094D\u0935\u093F\u0926\u0941\u0903\u0964<br> \u092E\u094B\u0939\u093F\u0924\u093E \u0926\u0947\u0935\u0917\u0928\u094D\u0927\u0930\u094D\u0935\u093E \u092E\u093F\u0925\u094D\u092F\u093E\u091C\u094D\u091E\u093E\u0928\u0947\u0928 \u0917\u0930\u094D\u0935\u093F\u0924\u093E\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0936\u094D\u0930\u0940\u0924\u0928\u094D\u0924\u094D\u0930\u0938\u0926\u094D\u092D\u093E\u0935\u0947\u093D\u092A\u093F</p><blockquote><p>\u092E\u0928\u094D\u0924\u094D\u0930\u093E\u0923\u093E\u0902 \u091C\u0940\u0935\u092D\u0942\u0924\u093E \u0924\u0941 \u092F\u093E \u0938\u094D\u092E\u0943\u0924\u093E \u0936\u0915\u094D\u0924\u093F\u0930\u0935\u094D\u092F\u092F\u093E\u0964<br> \u0924\u092F\u093E \u0939\u0940\u0928\u093E \u0935\u0930\u093E\u0930\u094B\u0939\u0947 \u0928\u093F\u0937\u094D\u092B\u0932\u093E\u0903 \u0936\u0930\u0926\u092D\u094D\u0930\u0935\u0924\u094D\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0936\u094D\u0930\u0940\u0936\u094D\u0930\u0940\u0915\u0923\u094D\u0920\u0940\u092F\u0938\u0902\u0939\u093F\u0924\u093E\u092F\u093E\u0902 \u0924\u0941</p><blockquote><p>\u092A\u0943\u0925\u0919\u094D\u092E\u0928\u094D\u0924\u094D\u0930\u0903 \u092A\u0943\u0925\u0919\u094D\u092E\u0928\u094D\u0924\u094D\u0930\u0940 \u0928 \u0938\u093F\u0926\u094D\u0927\u094D\u092F\u0924\u093F \u0915\u0926\u093E\u091A\u0928\u0964<br> \u091C\u094D\u091E\u093E\u0928\u092E\u0942\u0932\u092E\u093F\u0926\u0902 \u0938\u0930\u094D\u0935\u092E\u0928\u094D\u092F\u0925\u093E \u0928\u0948\u0935 \u0938\u093F\u0926\u094D\u0927\u094D\u092F\u0924\u093F\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u0941\u0915\u094D\u0924\u092E\u094D\u0964 \u090F\u0924\u091A\u094D\u091A \u0938\u094D\u092A\u0928\u094D\u0926\u0947</p><blockquote><p>\u0938\u0939\u093E\u0930\u093E\u0927\u0915\u091A\u093F\u0924\u094D\u0924\u0947\u0928 \u0924\u0947\u0928\u0948\u0924\u0947 \u0936\u093F\u0935\u0927\u0930\u094D\u092E\u093F\u0923\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F \u092D\u0919\u094D\u0917\u094D\u092F\u093E \u092A\u094D\u0930\u0924\u093F\u092A\u093E\u0926\u093F\u0924\u092E\u094D\u0965\u0967\u0965</p></div><hr><div class="trans"><p>Id\u0101n\u012B\u1E41 \u015B\u0101ktop\u0101ya\u1E25 pradar\u015Byate| Tatra \u015Baktirmantrav\u012Bryasph\u0101rar\u016Bpeti prathamonme\u1E63\u0101ntas\u016Btritatatsvar\u016Bpavivecanapura\u1E25saramunme\u1E63\u0101ntaram\u0101rabham\u0101\u1E47o mantrasvar\u016Bpa\u1E41 t\u0101vannir\u016Bpayati\u2014</p><blockquote><p><strong>Citta\u1E41 mantra\u1E25||1||</strong></p></blockquote><p>Cetyate vim\u1E5B\u015Byate&#39;nena para\u1E41 tattvamiti citta\u1E41 p\u016Br\u1E47asphuratt\u0101satattvapr\u0101s\u0101dapra\u1E47av\u0101divimar\u015Bar\u016Bpa\u1E41 sa\u1E41vedana\u1E41 tadeva mantryate guptamantarabhedena vim\u1E5B\u015Byate parame\u015Bvarar\u016Bpamaneneti k\u1E5Btv\u0101 mantra\u1E25| Ata eva ca parasphuratt\u0101tmakamananadharm\u0101tmat\u0101 bhedamayasa\u1E41s\u0101rapra\u015Baman\u0101tmakatr\u0101\u1E47adharmat\u0101 c\u0101sya nirucyate|</p><p>Atha ca mantradevat\u0101vimar\u015Baparatvena pr\u0101ptatats\u0101marasyam\u0101r\u0101dhakacittameva mantro na tu vicitravar\u1E47asa\u1E45gha\u1E6D\u1E6Dan\u0101m\u0101trakam| Yadukta\u1E41 \u015Br\u012Bmatsarvaj\xF1\u0101nottare</p><blockquote><p>Ucc\u0101ryam\u0101\u1E47\u0101 ye mantr\u0101 na mantr\u0101\u1E41\u015Bc\u0101pi t\u0101nvidu\u1E25|<br> Mohit\u0101 devagandharv\u0101 mithy\u0101j\xF1\u0101nena garvit\u0101\u1E25||</p></blockquote><p>iti| \u015Ar\u012Btantrasadbh\u0101ve&#39;pi</p><blockquote><p>Mantr\u0101\u1E47\u0101\u1E41 j\u012Bvabh\u016Bt\u0101 tu y\u0101 sm\u1E5Bt\u0101 \u015Baktiravyay\u0101|<br> Tay\u0101 h\u012Bn\u0101 var\u0101rohe ni\u1E63phal\u0101\u1E25 \u015Baradabhravat||</p></blockquote><p>iti| \u015Ar\u012B\u015Br\u012Bka\u1E47\u1E6Dh\u012Byasa\u1E41hit\u0101y\u0101\u1E41 tu</p><blockquote><p>P\u1E5Btha\u1E45mantra\u1E25 p\u1E5Btha\u1E45mantr\u012B na siddhyati kad\u0101cana|<br> J\xF1\u0101nam\u016Blamida\u1E41 sarvamanyath\u0101 naiva siddhyati||</p></blockquote><p>ityuktam| Etacca spande</p><blockquote><p>Sah\u0101r\u0101dhakacittena tenaite \u015Bivadharmi\u1E47a\u1E25||</p></blockquote><p>iti bha\u1E45gy\u0101 pratip\u0101ditam||1||</p></div><hr><p>\u0421\u0435\u0439\u0447\u0430\u0441 <em>(id\u0101n\u012Bm)</em>, [\u015A\u0101ktop\u0101ya,] \u043C\u0435\u0442\u043E\u0434\u044B <em>(up\u0101ya\u1E25)</em>, \u0438\u043C\u0435\u044E\u0449\u0438\u0435 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0435 \u043A \u015Aakti <em>(\u015B\u0101kta)</em><sup>1</sup>, \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u044E\u0442\u0441\u044F <em>(pradar\u015Byate)</em>|</p><p>\u0412\u0442\u043E\u0440\u0430\u044F <em>(antaram)</em> \u0413\u043B\u0430\u0432\u0430 <em>(unme\u1E63a)</em> \u0432 \u043F\u0435\u0440\u0432\u0443\u044E \u043E\u0447\u0435\u0440\u0435\u0434\u044C <em>(t\u0101vat)</em> \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u044F\u0435\u0442 <em>(nir\u016Bpayati)</em> \u043F\u0440\u0438\u0440\u043E\u0434\u0443 <em>(sva-r\u016Bpam)</em> \u043C\u0430\u043D\u0442\u0440\u044B <em>(mantra)</em>, \u043D\u0430\u0447\u0438\u043D\u0430\u044F <em>(\u0101rabham\u0101\u1E47a\u1E25)</em> \u0441 <em>(pura\u1E25saram)</em> \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F <em>(vivecana)</em> \u0435\u0435 --\u0442.\u0435. \u043C\u0430\u043D\u0442\u0440\u044B-- <em>(tad)</em> \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u044B\u0445 \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0441\u0442\u0438\u043A <em>(sva-r\u016Bpa)</em>, \u043A\u0430\u043A \u0437\u0430\u044F\u0432\u043B\u0435\u043D\u043E \u0432 \u043F\u043E\u0441\u043B\u0435\u0434\u043D\u0435\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435 <em>(s\u016Btrita anta)</em> \u041F\u0435\u0440\u0432\u043E\u0439 <em>(prathama)</em> \u0413\u043B\u0430\u0432\u044B <em>(unme\u1E63a)</em>. \u0412 \u044D\u0442\u043E\u043C [\u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435] <em>(tatra)</em> [\u043A\u0440\u0430\u0442\u043A\u043E \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F, \u0447\u0442\u043E] &quot;\u015Aakti <em>(\u015Bakti\u1E25)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u0435\u043C <em>(sph\u0101ra-r\u016Bp\u0101)</em> \u043F\u043E\u0440\u043E\u0436\u0434\u0430\u044E\u0449\u0435\u0433\u043E \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u0430 --\u043C\u043E\u0433\u0443\u0449\u0435\u0441\u0442\u0432\u0430, \u0438\u043B\u0438 \u0441\u0438\u043B\u044B-- <em>(v\u012Brya)</em> [\u0432\u0441\u0435\u0445] \u043C\u0430\u043D\u0442\u0440 <em>(mantra... iti)</em>&quot;\u2014</p><blockquote><p><strong>\u0423\u043C [\u0442\u043E\u0433\u043E, \u043A\u0442\u043E \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u0440\u0430\u0437\u043C\u044B\u0448\u043B\u044F\u0435\u0442 \u043D\u0430\u0434 \u0412\u044B\u0441\u0448\u0435\u0439 \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E] <em>(cittam)</em> [\u0435\u0441\u0442\u044C] \u041C\u0430\u043D\u0442\u0440\u0430 <em>(mantra\u1E25)</em>||1||</strong></p></blockquote><p>Citta --\u0432 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435-- <em>(cittam)</em> [\u2014 \u044D\u0442\u043E] &quot;\u0442\u043E, \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0447\u0435\u0433\u043E <em>(anena)</em> \u0412\u044B\u0441\u0448\u0438\u0439 <em>(param)</em> \u041F\u0440\u0438\u043D\u0446\u0438\u043F <em>(tattvam)</em> \u043E\u0431\u0434\u0443\u043C\u044B\u0432\u0430\u0435\u0442\u0441\u044F <em>(cetyate)</em> [\u0438] \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F <em>(vim\u1E5B\u015Byate... iti)</em>&quot;. [\u0422.\u0435. \u044D\u0442\u043E] \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 <em>(sa\u1E41vedanam)</em>, \u0447\u044C\u044F \u0444\u043E\u0440\u043C\u0430, \u0438\u043B\u0438 \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(r\u016Bpam)</em> [\u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437] \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F <em>(vimar\u015Ba)</em> Pr\u0101s\u0101da <em>(pr\u0101s\u0101da)</em>, Pra\u1E47ava <em>(pra\u1E47ava)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em><sup>2</sup></p><p>, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C\u044E <em>(satattva)</em> \u0421\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E\u0439 <em>(p\u016Br\u1E47a)</em> Sphuratt\u0101 --\u0442.\u0435. &quot;\u043F\u0443\u043B\u044C\u0441\u0438\u0440\u0443\u044E\u0449\u0435\u0439 \u0432\u0441\u043F\u044B\u0448\u043A\u0438&quot;, \u044D\u0442\u043E \u044D\u043F\u0438\u0442\u0435\u0442 \u015Aakti, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u0430\u0448\u0438\u043C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C-- <em>(sphuratt\u0101)</em>. \u042D\u0442\u043E <em>(tad)</em> \u0441\u0430\u043C\u043E\u0435 <em>(eva)</em> [Citta \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043C\u0430\u043D\u0442\u0440\u043E\u0439 <em>(mantra\u1E25)</em>; [\u0438 \u043C\u0430\u043D\u0442\u0440\u0430] \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u0442\u0441\u044F --\u0442.\u0435. \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044F-- <em>(iti k\u1E5Btv\u0101)</em> &quot;\u0442\u0435\u043C, \u043F\u0440\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0447\u0435\u0433\u043E <em>(anena)</em> \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(r\u016Bpam)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E <em>(parama)</em> \u0413\u043E\u0441\u043F\u043E\u0434\u0430 <em>(\u012B\u015Bvara)</em> \u043E\u0431\u0434\u0443\u043C\u044B\u0432\u0430\u0435\u0442\u0441\u044F <em>(mantryate)</em> \u0432\u0442\u0430\u0439\u043D\u0435 <em>(guptam)</em>, \u0442.\u0435. [\u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0447\u0435\u0433\u043E, \u044D\u0442\u0430 \u043F\u0440\u0438\u0440\u043E\u0434\u0430] \u0438\u0441\u0441\u043B\u0435\u0434\u0443\u0435\u0442\u0441\u044F <em>(vim\u1E5B\u015Byate)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435 <em>(antar)</em> \u0432 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435 <em>(abhedena... iti)</em> <sup>3</sup> &quot;|</p><p>\u0418\u0441\u0445\u043E\u0434\u044F \u0438\u0437 \u044D\u0442\u043E\u0433\u043E \u0441\u0430\u043C\u043E\u0433\u043E [\u0444\u0430\u043A\u0442\u0430] <em>(atas eva ca)</em>, \u0438\u043D\u0442\u0435\u0440\u043F\u0440\u0435\u0442\u0438\u0440\u0443\u0435\u0442\u0441\u044F, \u0438\u043B\u0438 \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0435\u0442\u0441\u044F [\u044D\u0442\u0438\u043C\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0438 \u0438 \u0430\u043A\u0440\u043E\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u0438]<em>(nirucyate)</em> \u0435\u0435 --\u0442.\u0435. \u043C\u0430\u043D\u0442\u0440\u044B-- <em>(asya)</em> \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0441\u0442\u0438\u043A\u0430 <em>(dharma-\u0101tmat\u0101)</em> manana, [\u0438\u043B\u0438 \u0440\u0430\u0437\u043C\u044B\u0448\u043B\u0435\u043D\u0438\u0435 \u043D\u0430\u0434] <em>(manana)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 <em>(\u0101tmaka)</em> \u0412\u044B\u0441\u0448\u0435\u0439 <em>(para)</em> Sphuratt\u0101 --\u0438\u043B\u0438 &quot;\u043F\u0443\u043B\u044C\u0441\u0438\u0440\u0443\u044E\u0449\u0435\u0439 \u0432\u0441\u043F\u044B\u0448\u043A\u0438&quot;, \u043A\u0430\u043A \u0443\u043F\u043E\u043C\u0438\u043D\u0430\u043B\u043E\u0441\u044C \u0440\u0430\u043D\u0435\u0435; \u043A\u043E\u0440\u043E\u0447\u0435, &quot;\u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435&quot;-- <em>(sphuratt\u0101)</em> \u0442\u0430\u043A\u0436\u0435 \u043A\u0430\u043A \u0438 <em>(ca)</em> [\u0435\u0435 \u0434\u0440\u0443\u0433\u0430\u044F] \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0441\u0442\u0438\u043A\u0430 <em>(dharmat\u0101)</em> tr\u0101\u1E47a, [\u0438\u043B\u0438 \u0437\u0430\u0449\u0438\u0442\u0430] <em>(tr\u0101\u1E47a)</em>, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0430\u044F \u0438\u0437 <em>(\u0101tmaka)</em> \u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0435\u043D\u0438\u044F <em>(pra\u015Bamana)</em> \u0421\u0430\u043C\u0441\u0430\u0440\u044B (Sa\u1E41s\u0101ra) --\u0442.\u0435. \u0442\u0440\u0430\u043D\u0441\u043C\u0438\u0433\u0440\u0430\u0446\u0438\u043E\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F-- <em>(sa\u1E41s\u0101ra)</em>, \u043F\u043E\u043B\u043D\u043E\u0433\u043E <em>(maya)</em> \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0439, \u0438\u043B\u0438 \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438 <em>(bheda)</em> <sup>4</sup>|</p><p>\u041A\u0440\u043E\u043C\u0435 \u0442\u043E\u0433\u043E <em>(atha ca)</em>, [\u044D\u0442\u043E] \u043F\u0440\u043E\u0441\u0442\u043E <em>(eva)</em> \u0443\u043C <em>(cittam)</em> \u043F\u0440\u0435\u0434\u0430\u043D\u043D\u043E\u0433\u043E <em>(\u0101r\u0101dhaka)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0434\u043E\u0441\u0442\u0438\u0433 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0430 <em>(pr\u0101pta... s\u0101marasyam)</em> \u0441 \u042D\u0442\u0438\u043C--\u0412\u044B\u0441\u0448\u0438\u043C \u042F-- <em>(tad)</em> \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043F\u043E\u043B\u043D\u043E\u043C\u0443 \u043F\u043E\u0441\u0432\u044F\u0449\u0435\u043D\u0438\u044E \u0441\u0435\u0431\u044F <em>(paratvena)</em> \u0438\u043D\u0442\u0435\u043D\u0441\u0438\u0432\u043D\u043E\u043C\u0443 \u043E\u0441\u043E\u0437\u043D\u0430\u0432\u0430\u043D\u0438\u044E <em>(vimar\u015Ba)</em> \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0430 \u043C\u0430\u043D\u0442\u0440\u044B <em>(mantra devat\u0101)</em>, [\u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043C\u0430\u043D\u0442\u0440\u043E\u0439 <em>(mantra\u1E25)</em>, \u0430 \u043D\u0435 <em>(na tu)</em> \u0442\u0430\u043A \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u043E\u0439 <em>(n\u0101ma-atrakam)</em> \u0441\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0441\u0442\u044C\u044E <em>(sa\u1E45gha\u1E6D\u1E6Da)</em> \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0430 <em>(vicitra)</em> \u0431\u0443\u043A\u0432 <em>(var\u1E47a)</em>|</p><p>\u042D\u0442\u043E <em>(yad)</em> \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam)</em> \u0432 \u043D\u0430\u0438\u0431\u043E\u043B\u0435\u0435 \u043F\u043E\u0447\u0438\u0442\u0430\u0435\u043C\u043E\u043C <em>(\u015Br\u012Bmat)</em> Sarvaj\xF1\u0101nottara <em>(sarvaj\xF1\u0101nottare)</em>:</p><blockquote><p>&quot;[\u042D\u0442\u043E] \u043D\u0435 <em>(na)</em> \u043C\u0430\u043D\u0442\u0440\u044B <em>(mantr\u0101\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 <em>(ye)</em> \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u044F\u0442\u0441\u044F <em>(ucc\u0101ryam\u0101\u1E47\u0101\u1E25)</em>. \u0418 <em>(ca)</em> \u0434\u0430\u0436\u0435 <em>(api)</em> \u043E\u0431\u043C\u0430\u043D\u0443\u0442\u044B\u0435 <em>(mohit\u0101\u1E25)</em> [\u0438] \u0442\u0449\u0435\u0441\u043B\u0430\u0432\u043D\u044B\u0435 <em>(garvit\u0101\u1E25)</em> \u0431\u043E\u0433\u0438 \u0438 \u043D\u0435\u0431\u0435\u0441\u043D\u044B\u0435 \u043C\u0443\u0437\u044B\u043A\u0430\u043D\u0442\u044B <em>(deva-gandharv\u0101\u1E25)</em>, \u0438\u0437-\u0437\u0430 \u0438\u043B\u043B\u044E\u0437\u043E\u0440\u043D\u043E\u0433\u043E \u0437\u043D\u0430\u043D\u0438\u044F <em>(mithy\u0101-j\xF1\u0101nena)</em>, \u0441\u0447\u0438\u0442\u0430\u044E\u0442 <em>(vidu\u1E25)</em> \u0438\u0445 <em>(t\u0101n)</em> \u043C\u0430\u043D\u0442\u0440\u0430\u043C\u0438 <em>(mantr\u0101n... iti)</em>&quot;||</p></blockquote><p>[\u0422\u0430 \u0436\u0435 \u0438\u0441\u0442\u0438\u043D\u0430] \u0442\u0430\u043A\u0436\u0435 <em>(api)</em> [\u0432\u044B\u0441\u043A\u0430\u0437\u0430\u043D\u0430] \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u043C Tantrasadbh\u0101va <em>(\u015Br\u012B-tantrasadbh\u0101ve)</em>:</p><blockquote><p>&quot;\u041E\u043D\u0430, \u043A\u043E\u0442\u043E\u0440\u0430\u044F <em>(y\u0101)</em> \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044F <em>(sm\u1E5Bt\u0101)</em> \u0432\u0435\u0447\u043D\u043E\u0439 <em>(avyay\u0101)</em> \u015Aakti <em>(\u015Bakti)</em> --\u0442.\u0435. \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435-- \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(bh\u016Bt\u0101)</em> \u0431\u0435\u0437\u0443\u0441\u043B\u043E\u0432\u043D\u043E <em>(tu)</em> \u0434\u0443\u0448\u043E\u0439 <em>(j\u012Bva)</em> \u043C\u0430\u043D\u0442\u0440 <em>(mantr\u0101\u1E47\u0101m)</em>. \u041E \u041F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u0430\u044F <em>(vara-\u0101rohe)</em>!, \u0431\u0435\u0437 <em>(h\u012Bn\u0101\u1E25)</em> \u041D\u0435\u0435 <em>(tay\u0101)</em>, \u043E\u043D\u0438 --\u0442.\u0435. \u043C\u0430\u043D\u0442\u0440\u044B-- \u0431\u0435\u0441\u043F\u043B\u043E\u0434\u043D\u044B <em>(ni\u1E63phal\u0101\u1E25)</em> \u043A\u0430\u043A <em>(vat)</em> \u043E\u0441\u0435\u043D\u043D\u0438\u0435 <em>(\u015Barad)</em> \u043E\u0431\u043B\u0430\u043A\u0430 <em>(abhra... iti)</em> --\u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u044D\u0442\u0438 \u043E\u0431\u043B\u0430\u043A\u0430 \u0441\u043E\u0432\u0441\u0435\u043C \u043D\u0435 \u0434\u0430\u044E\u0442 \u0434\u043E\u0436\u0434\u044F--&quot;||</p></blockquote><p>\u0411\u044B\u043B\u043E \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam)</em> \u0432 \u043E\u0447\u0435\u043D\u044C \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C Ka\u1E47\u1E6Dh\u012Byasa\u1E41hit\u0101 <em>(\u015Br\u012B-\u015Br\u012B-ka\u1E47\u1E6Dh\u012Byasa\u1E41hit\u0101y\u0101m tu)</em>:</p><blockquote><p>&quot;[\u0415\u0441\u043B\u0438] \u043C\u0430\u043D\u0442\u0440\u0430 <em>(mantra\u1E25)</em> [\u0438] \u043F\u0440\u0430\u043A\u0442\u0438\u043A \u043C\u0430\u043D\u0442\u0440\u044B <em>(mantr\u012B)</em> \u043E\u0442\u043B\u0438\u0447\u043D\u044B \u0434\u0440\u0443\u0433 \u043E\u0442 \u0434\u0440\u0443\u0433\u0430 <em>(p\u1E5Bthak... p\u1E5Bthak)</em>, [\u0442\u043E\u0433\u0434\u0430 \u0442\u0430\u043A\u0430\u044F \u043C\u0430\u043D\u0442\u0440\u0430]\u043D\u0438\u043A\u043E\u0433\u0434\u0430 <em>(na... kad\u0101cana)</em> \u043D\u0435 \u043F\u0440\u0438\u043D\u0435\u0441\u0435\u0442 \u043F\u043B\u043E\u0434\u0430 <em>(siddhyati)</em>. \u0412\u0441\u0435 <em>(sarvam)</em> \u044D\u0442\u043E <em>(idam)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u043A\u043E\u0440\u043D\u0435\u043C <em>(m\u016Blam)</em> \u0437\u043D\u0430\u043D\u0438\u0439 <em>(j\xF1\u0101na)</em> [\u0432 \u041C\u0430\u043D\u0442\u0440\u0430-\u0439\u043E\u0433\u0435.] \u042D\u0442\u043E \u043D\u0435 <em>(na eva)</em> \u043F\u0440\u0438\u043D\u0435\u0441\u0435\u0442 \u0443\u0441\u043F\u0435\u0445\u0430 <em>(siddhyati)</em> [\u0432 \u0441\u043B\u0443\u0447\u0430\u0435 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0438] \u0432 \u0442\u0430\u043A\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435 <em>(anyath\u0101)</em>&quot;||</p></blockquote><p>\u0412 Spandak\u0101rik\u0101-s <em>(spande)</em> \u044D\u0442\u043E <em>(etad ca)</em> \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0435\u0442\u0441\u044F <em>(pratip\u0101ditam)</em> \u043A\u043E\u0441\u0432\u0435\u043D\u043D\u043E <em>(bha\u1E45gy\u0101)</em>:</p><blockquote><p>&quot;... \u0432\u043C\u0435\u0441\u0442\u0435 <em>(saha)</em> \u0441 \u0443\u043C\u043E\u043C <em>(cittena)</em> [\u0441\u0430\u043C\u0438\u0445] \u043F\u043E\u043A\u043B\u043E\u043D\u044F\u044E\u0449\u0438\u0445\u0441\u044F <em>(\u0101r\u0101dhaka)</em>. \u0421\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E <em>(tena)</em>, \u044D\u0442\u0438 [\u041C\u0430\u043D\u0442\u0440\u044B] <em>(ete)</em> \u0438\u043C\u0435\u044E\u0442 \u043F\u0440\u0438\u0440\u043E\u0434\u0443 <em>(dharmi\u1E47a\u1E25)</em> \u0428\u0438\u0432\u044B <em>(\u015Biva... iti)</em>&quot;||<br> [\u0421\u043C. Spandak\u0101rik\u0101-s II, 2]</p></blockquote><p>||1||</p><hr><ol><li><p>\u041A\u043E\u0440\u043E\u0447\u0435, \u043D\u0430\u0447\u0430\u043B\u0430\u0441\u044C \u0412\u0442\u043E\u0440\u0430\u044F \u0413\u043B\u0430\u0432\u0430, \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0430\u044F\u0441\u044F \u043A \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430\u043C, \u0438\u043B\u0438 \u043C\u0435\u0442\u043E\u0434\u0430\u043C, \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044E\u0449\u0438\u043C \u0442\u043E\u0447\u043A\u0443 \u0437\u0440\u0435\u043D\u0438\u044F \u015Aakti.</p></li><li><p>Pr\u0101s\u0101da \u2014 \u044D\u0442\u043E \u0442\u0435\u0445\u043D\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0438\u043C\u044F \u043C\u0430\u043D\u0442\u0440\u044B Sau\u1E25, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043F\u043E\u0434\u0440\u043E\u0431\u043D\u043E \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u043C\u043D\u043E\u0439 \u0432 Par\u0101pr\u0101ve\u015Bik\u0101. \u0421\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u043D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u043E \u0432\u0438\u0434\u043E\u0432 Pra\u1E47ava, \u043D\u043E \u0432 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435 \u044D\u0442\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 \u015Aaivapra\u1E47ava (\u0442.\u0435. H\u016Bm\u0310).</p></li><li><p>\u0427\u0435\u0440\u0435\u0437 \u043C\u0430\u043D\u0442\u0440\u0443 \u043A\u0430\u0436\u0434\u044B\u0439 \u0432\u0442\u0430\u0439\u043D\u0435 \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442 \u043F\u0440\u0438\u0440\u043E\u0434\u0443 \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u0430, \u0442.\u0435. \u0440\u0430\u0437\u043C\u044B\u0448\u043B\u044F\u0435\u0442 \u043D\u0430\u0434 \u043D\u0435\u0439 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435, \u0432 \u0442\u043E \u0436\u0435 \u0441\u0430\u043C\u043E\u0435 \u0432\u0440\u0435\u043C\u044F \u0441\u043E\u0445\u0440\u0430\u043D\u044F\u044F \u043F\u043E\u043B\u043D\u043E\u0435 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u043E \u0441 \u0413\u043E\u0441\u043F\u043E\u0434\u043E\u043C (\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u043E\u043C \u043C\u0430\u043D\u0442\u0440\u044B) \u0438 \u0441\u0430\u043C\u043E\u0439 \u043C\u0430\u043D\u0442\u0440\u043E\u0439. \u0418 \u0432 \u044D\u0442\u043E\u043C \u0437\u0430\u043A\u043B\u044E\u0447\u0430\u0435\u0442\u0441\u044F \u0441\u0435\u043A\u0440\u0435\u0442 \u043F\u043E\u0432\u0442\u043E\u0440\u0435\u043D\u0438\u044F \u043C\u0430\u043D\u0442\u0440\u044B: \u0432\u044B \u0441\u0430\u043C\u0438, \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u0438 \u043C\u0430\u043D\u0442\u0440\u0430 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0442 \u0432 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435. \u0415\u0441\u043B\u0438 \u0447\u0435\u043B\u043E\u0432\u0435\u043A, \u043F\u043E\u0432\u0442\u043E\u0440\u044F\u044E\u0449\u0438\u0439 \u043C\u0430\u043D\u0442\u0440\u0443 \u043D\u0435 \u0434\u0435\u043B\u0430\u0435\u0442 \u044D\u0442\u043E\u0433\u043E (\u0442.\u0435. \u043E\u043D \u043D\u0435 \u043C\u043E\u0436\u0435\u0442 \u0434\u043E\u0441\u0442\u0438\u0447\u044C \u0438 \u0443\u0434\u0435\u0440\u0436\u0430\u0442\u044C \u044D\u0442\u043E \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u043E \u043D\u0435\u043E\u0442\u044A\u0435\u043C\u043B\u0435\u043C\u043E\u043C \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435 \u043C\u0435\u0436\u0434\u0443 \u043D\u0438\u043C, \u0413\u043E\u0441\u043F\u043E\u0434\u043E\u043C \u0438 \u043C\u0430\u043D\u0442\u0440\u043E\u0439), \u0442\u043E\u0433\u0434\u0430 \u043C\u0430\u043D\u0442\u0440\u0430 \u043D\u0435 \u043F\u0440\u0438\u043D\u043E\u0441\u0438\u0442 \u043D\u0430\u0434\u043B\u0435\u0436\u0430\u0449\u0438\u0445 \u043F\u043B\u043E\u0434\u043E\u0432. \u0418 \u043D\u0435\u0442 \u043D\u0438\u043A\u0430\u043A\u0438\u0445 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u0439 \u0432 \u044D\u0442\u043E\u043C.</p></li><li><p>\u042D\u0442\u0438\u043C\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0438, \u0442\u0435\u0440\u043C\u0438\u043D &quot;mantra&quot; \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0438\u0437 \u043A\u043E\u0440\u043D\u044F &quot;man&quot; (\u0434\u0443\u043C\u0430\u0442\u044C). \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u043E\u0434\u043D\u0438\u043C \u0438\u0437 \u043F\u0435\u0440\u0432\u044B\u0445 \u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u044B\u0445 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0439 \u044D\u0442\u043E\u0433\u043E \u0441\u043B\u043E\u0432\u0430 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F &quot;\u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442 \u043C\u044B\u0441\u043B\u0438&quot;. \u041D\u043E \u0430\u043A\u0440\u043E\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u0438, &quot;mantra&quot; \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0438\u0437 manana + tr\u0101\u1E47a, \u0447\u0442\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u043E\u0442\u0440\u0430\u0436\u0435\u043D\u0438\u0435/\u0440\u0430\u0437\u043C\u044B\u0448\u043B\u0435\u043D\u0438\u0435 + \u0437\u0430\u0449\u0438\u0442\u0430&quot;. \u0418\u0437\u0432\u0435\u0441\u0442\u043D\u043E\u0435 \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u0438\u0435 &quot;\u043C\u0430\u043D\u0442\u0440\u044B&quot; \u043A\u0430\u043A &quot; \u092E\u0928\u0928\u093E\u0924\u094D\u0924\u094D\u0930\u093E\u092F\u0924 \u0907\u0924\u093F \u092E\u0928\u094D\u0924\u094D\u0930\u0903&quot; - &quot;manan\u0101ttr\u0101yata iti mantra\u1E25&quot;, \u0438\u043B\u0438 &quot;\u043C\u0430\u043D\u0442\u0440\u0430 \u2014 \u044D\u0442\u043E \u0442\u043E, \u0447\u0442\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0437\u0430\u0449\u0438\u0442\u043E\u0439 \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u0440\u0430\u0437\u043C\u044B\u0448\u043B\u0435\u043D\u0438\u044F&quot;, \u044F\u0441\u043D\u043E \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u0430\u043A\u0440\u043E\u0441\u0442\u0438\u0445. \u041A\u043E\u0440\u043E\u0447\u0435: \u043C\u0430\u043D\u0442\u0440\u0430 \u2014 \u044D\u0442\u043E \u0442\u043E, \u0447\u0442\u043E \u0437\u0430\u0449\u0438\u0449\u0430\u0435\u0442 \u0442\u043E\u0433\u043E, \u043A\u0442\u043E \u043E\u0442\u0440\u0430\u0436\u0430\u0435\u0442\u0441\u044F \u0432 \u043D\u0435\u0439 (\u0442.\u0435. \u043A\u0442\u043E \u0440\u0430\u0437\u043C\u044B\u0448\u043B\u044F\u0435\u0442 \u043D\u0430\u0434 \u043D\u0435\u0439). \u041C\u0430\u043D\u0442\u0440\u0430 \u0437\u0430\u0449\u0438\u0449\u0430\u0435\u0442 \u0432 \u0442\u043E\u043C \u0441\u043C\u044B\u0441\u043B\u0435, \u0447\u0442\u043E \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0430\u0435\u0442 \u0442\u0440\u0430\u043D\u0441\u043C\u0438\u0433\u0440\u0430\u0446\u0438\u043E\u043D\u043D\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435, \u0442.\u0435. \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u044E\u0449\u0435\u0435\u0441\u044F \u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u0438\u0435 \u0441 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u043C\u0435\u043D\u044F\u044E\u0449\u0438\u043C\u0438\u0441\u044F \u043C\u044B\u0441\u043B\u044F\u043C\u0438, \u0447\u0443\u0432\u0441\u0442\u0432\u0430\u043C\u0438 \u0438 \u0442.\u0434., \u0447\u0442\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u0440\u0438\u0437\u043D\u0430\u043A\u043E\u043C \u0440\u0430\u0431\u0441\u0442\u0432\u0430. \u0422\u0430\u043A \u0438\u043B\u0438 \u0438\u043D\u0430\u0447\u0435, \u0442\u0440\u0430\u043D\u0441\u043C\u0438\u0433\u0440\u0430\u0446\u0438\u043E\u043D\u043D\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435 \u0442\u0430\u043A\u0436\u0435 \u043F\u043E\u043D\u0438\u043C\u0430\u0435\u0442\u0441\u044F \u043A\u0430\u043A \u0440\u043E\u0434\u0438\u0432\u0448\u0438\u0439\u0441\u044F, \u0447\u0442\u043E\u0431\u044B \u0443\u043C\u0435\u0440\u0435\u0442\u044C, \u0438 \u0443\u043C\u0435\u0440\u0448\u0438\u0439, \u0447\u0442\u043E\u0431\u044B \u043F\u0435\u0440\u0435\u0440\u043E\u0434\u0438\u0442\u044C\u0441\u044F.</p></li></ol></div>',1),i=[p];function n(o,u,s,v,d,c){return m(),e("div",null,i)}var q=a(r,[["render",n]]);export{k as __pageData,q as default};
